    type eventType: CGEventType,
    event: CGEvent,
    userInfo: UnsafeMutableRawPointer?
) -> Unmanaged<CGEvent>? {
    if eventType == .tapDisabledByTimeout || eventType == .tapDisabledByUserInput {
